import { useState, useCallback, useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import RecordItem from "../Earning/RecordItem";
import type { RecordItem as RecordItemType } from "../Earning/types";
import { buildRecordItem, isCallChangeType } from "../Earning/utils";
import { getPwaUserBalanceChangeHistory, listCallOrderByRange } from "@/http/earningApi";
import type { CallOrderInfo } from "@sitin/api-proto/gen/archat_api/user_api";
import { tzDayRange, tzDateKey } from "@/utils/timezone";
import backIcon from "@/assets/images/common/ic_back_white.svg";
import Spinner from "@/components/Spinner";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

export default function Records() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const selectedDate = searchParams.get("date");

  const [records, setRecords] = useState<RecordItemType[]>([]);
  const [loading, setLoading] = useState(false);

  // 埋点：收益记录页面展示
  useEffect(() => {
    bpTrack(EventName.pwa_earnings_records_page_show, {
      date: selectedDate || "",
    });
  }, [selectedDate]);

  useEffect(() => {
    if (!selectedDate) return;

    let cancelled = false;

    async function fetchDayRecords() {
      setLoading(true);
      try {
        const { startSec, endSec } = tzDayRange(selectedDate!);
        const [historyRes, ordersRes] = await Promise.all([
          getPwaUserBalanceChangeHistory(startSec, endSec),
          listCallOrderByRange(startSec, endSec),
        ]);

        if (cancelled) return;

        const histories = historyRes?.histories ?? [];
        const orders = ordersRes?.orders ?? [];

        // 按日期索引订单
        const ordersByDate = new Map<string, typeof orders>();
        for (const order of orders) {
          if (!order.createAt) continue;
          const key = tzDateKey(order.createAt * 1000);
          const list = ordersByDate.get(key) ?? [];
          list.push(order);
          ordersByDate.set(key, list);
        }

        const items: RecordItemType[] = [];
        const usedOrderIds = new Set<number>();
        for (const h of histories) {
          const changeTimeSec = h.changeTime ?? 0;
          if (changeTimeSec === 0) continue;
          const dateKey = tzDateKey(changeTimeSec * 1000);
          const changeType = h.type ?? 0;
          const isCall = isCallChangeType(changeType);

          let matchingOrders: CallOrderInfo[] = [];
          if (isCall) {
            const dayOrders = ordersByDate.get(dateKey) ?? [];
            // 按 createAt 与 changeTime 的时间差找最近的未匹配 order
            let bestOrder: CallOrderInfo | null = null;
            let bestDiff = Infinity;
            for (const o of dayOrders) {
              if (o.id != null && usedOrderIds.has(o.id)) continue;
              const diff = Math.abs((o.createAt ?? 0) - changeTimeSec);
              if (diff < bestDiff) {
                bestDiff = diff;
                bestOrder = o;
              }
            }
            if (bestOrder) {
              if (bestOrder.id != null) usedOrderIds.add(bestOrder.id);
              matchingOrders = [bestOrder];
            }
          }

          items.push(buildRecordItem(h, matchingOrders, dateKey));
        }

        items.sort((a, b) => (b.time ?? 0) - (a.time ?? 0));
        setRecords(items);
      } catch (err) {
        console.error("Failed to fetch day records:", err);
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    fetchDayRecords();
    return () => {
      cancelled = true;
    };
  }, [selectedDate]);

  const toggleExpand = useCallback((id: string) => {
    setRecords((prev) => prev.map((r) => (r.id === id ? { ...r, expanded: !r.expanded } : r)));
  }, []);

  const total = records.reduce((sum, r) => sum + r.amount, 0).toFixed(2);

  return (
    <div className="flex flex-col h-full overflow-hidden animate-fade-in bg-gradient-to-b from-[#1375FF] to-[#3EB2FF]">
      <div className="flex items-center justify-center relative px-4 shrink-0 pt-[calc(var(--sat,0px)+12px)] pb-3 ">
        <button className="absolute left-4 p-2 bg-transparent border-none" onClick={() => navigate(-1)}>
          <img src={backIcon} alt="Back" className="w-6 h-6" />
        </button>
        <span className="text-white text-2xl font-[800]" style={{ fontFamily: "Pangram, RacingSansOne, sans-serif" }}>
          Records
        </span>
      </div>

      <div className="flex-1 overflow-y-auto pb-5 rounded-t-2xl bg-[#F5F9FF] mt-4 relative z-[1]  ">
        {loading ? (
          <div className="flex items-center justify-center h-40">
            <Spinner />
          </div>
        ) : records.length > 0 ? (
          <div className="m-4 rounded-xl bg-white overflow-hidden">
            <div className="flex justify-between items-center p-4 border-b border-black/5">
              <span className="text-sm font-bold text-brand-dark">{selectedDate}</span>
              <span className="text-sm font-bold text-brand-dark">${total}</span>
            </div>
            {records.map((item) => (
              <RecordItem key={item.id} item={item} onToggleExpand={toggleExpand} />
            ))}
          </div>
        ) : (
          <div className="flex items-center justify-center h-40 text-[#A2AFCA] text-sm">No records</div>
        )}
      </div>
    </div>
  );
}
